<template>
    <div class="search-results-page">
        <loader :is-visible="isLoading"></loader>
        
        <div class="container-fluid p-0">
            <!-- Header -->
            <div class="row mb-3">
                <div class="col-12">
                    <div class="d-flex justify-content-between align-items-center">
                        <div>
                            <h4 class="mb-1">Results for <mark>{{ searchQuery }}</mark></h4>
                            <nav aria-label="breadcrumb">
                                <ol class="breadcrumb mb-0">
                                    <li class="breadcrumb-item">
                                        <a href="javascript:;" @click="goHome">Home</a>
                                    </li>
                                    <li class="breadcrumb-item active" aria-current="page">Search Results</li>
                                </ol>
                            </nav>
                        </div>
                        <div>
                            <a href="javascript:;" class="btn btn-secondary" @click="goBack">
                                <em class="fa fa-arrow-left mr-2"></em>{{ $t('Back') || 'Back' }}
                            </a>
                        </div>
                    </div>
                </div>
            </div>

            <!-- Module Filter -->
            <div class="row mb-3" v-if="availableModules.length > 0">
                <div class="col-12">
                    <div class="card module-filter-card">
                        <div class="card-body">
                            <div class="module-filters-container">
                                <div class="module-filters-header">
                                    <div class="search-filters">
                                        <select class="filter-dropdown module-dropdown" v-model="selectedModule" @change="onModuleFilterChange">
                                            <option value="">All Modules</option>
                                            <option v-for="module in availableModules" :key="module.value" :value="module.value">{{ module.text }}</option>
                                        </select>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <!-- Results List -->
            <div class="row">
                <div class="col-12">
                    <div class="card">
                        <div class="card-body p-0">
                            <!-- Loading State -->
                            <div v-if="isLoading" class="text-center p-5">
                                <em class="fa fa-spinner fa-spin fa-2x"></em>
                                <p class="mt-2">{{ $t('Loading') || 'Loading...' }}</p>
                            </div>

                            <!-- Results -->
                            <div v-else-if="displayedResults.length > 0" class="search-results-container">
                                <div 
                                    v-for="(result, index) in displayedResults" 
                                    :key="result.id || index"
                                    class="search-result-item"
                                   
                                >
                                    <div class="result-icon">
                                        <em :class="'fa fa-' + (result.icon || 'file-text-o')"></em>
                                    </div>
                                    <div class="result-content">
                                        <div class="result-main">
                                            <a 
                                                v-if="getResultId(result) && result.url" 
                                                :href="result.url" 
                                                class="result-id-link"
                                                @click.stop="navigateToResult(result)"
                                                v-html="highlightText(getResultId(result), searchQuery)"  @click="navigateToResult(result)"
                                            ></a>
                                            <div class="result-id" v-else-if="getResultId(result)" v-html="highlightText(getResultId(result), searchQuery)"></div>
                                            <div class="result-description" v-if="getResultDescription(result)" v-html="highlightText(getResultDescription(result), searchQuery)"></div>
                                        </div>
                                        <div class="result-meta">
                                            <template v-if="isInvoiceResult(result)">
                                                <span v-if="getParsedField(result, 'bill_issue_date')" class="meta-item">
                                                    <span class="meta-label">Issued Date:</span>
                                                    <span class="meta-value">{{ formatDate(getParsedField(result, 'bill_issue_date')) }}</span>
                                                </span>
                                                <span v-if="getParsedField(result, 'bill_net_total')" class="meta-item">
                                                    <span class="meta-label">Amount:</span>
                                                    <span class="meta-value">{{ formatCurrency(getParsedField(result, 'bill_net_total')) }}</span>
                                                </span>
                                                <span v-if="getParsedField(result, 'billing_division')" class="meta-item">
                                                    <span class="meta-label">Invoice Grouping:</span>
                                                    <span class="meta-value">{{ getParsedField(result, 'billing_division') }}</span>
                                                </span>
                                                <span v-if="getParsedField(result, 'status_name')" class="meta-item">
                                                    <span class="meta-label">Status:</span>
                                                    <span class="meta-value">{{ getParsedField(result, 'status_name') }}</span>
                                                </span>
                                                <span v-if="getParsedField(result, 'project_name')" class="meta-item">
                                                    <span class="meta-label">Project:</span>
                                                    <span class="meta-value">{{ getParsedField(result, 'project_name') }}</span>
                                                </span>
                                            </template>
                                            <template v-else-if="isUserResult(result)">
                                                <span v-if="getParsedField(result, 'user_id')" class="meta-item">
                                                    <span class="meta-label">User ID:</span>
                                                    <span class="meta-value" v-html="highlightText(getParsedField(result, 'user_id'), searchQuery)"></span>
                                                </span>
                                                <span v-if="getParsedField(result, 'usre_name')" class="meta-item">
                                                    <span class="meta-label">User Name:</span>
                                                    <span class="meta-value" v-html="highlightText(getParsedField(result, 'usre_name'), searchQuery)"></span>
                                                </span>
                                                <span v-if="getParsedField(result, 'contract_name')" class="meta-item">
                                                    <span class="meta-label">Contract:</span>
                                                    <span class="meta-value" v-html="highlightText(getParsedField(result, 'contract_name'), searchQuery)"></span>
                                                </span>
                                                <span v-if="getParsedField(result, 'status_name')" class="meta-item">
                                                    <span class="meta-label">Status:</span>
                                                    <span class="meta-value">{{ getParsedField(result, 'status_name') }}</span>
                                                </span>
                                            </template>
                                            <template v-else>
                                                <span v-if="getParsedField(result, 'bill_issue_date') || result.issuedDate" class="meta-item">
                                                    <span class="meta-label">Issued Date:</span>
                                                    <span class="meta-value">{{ formatDate(getParsedField(result, 'bill_issue_date') || result.issuedDate) }}</span>
                                                </span>
                                                <span v-if="getParsedField(result, 'bill_net_total') || result.amount" class="meta-item">
                                                    <span class="meta-label">Amount:</span>
                                                    <span class="meta-value">{{ formatCurrency(getParsedField(result, 'bill_net_total') || result.amount) }}</span>
                                                </span>
                                                <span v-if="getParsedField(result, 'billing_division') || result.invoiceGrouping" class="meta-item">
                                                    <span class="meta-label">Invoice Grouping:</span>
                                                    <span class="meta-value">{{ getParsedField(result, 'billing_division') || result.invoiceGrouping }}</span>
                                                </span>
                                            </template>
                                        </div>
                                    </div>
                                    <!-- <div class="result-actions" v-if="result.type === 'Invoice' || result.type === 'Talygen_bill'">
                                        <a 
                                            href="javascript:;" 
                                            class="action-btn attach-btn" 
                                            title="Attach"
                                            @click.stop="handleAttach(result)"
                                        >
                                            <em class="fa fa-paperclip"></em>
                                        </a>
                                        <button 
                                            class="btn btn-sm btn-primary summarize-btn"
                                            @click.stop="handleSummarize(result)"
                                        >
                                            Summarize
                                        </button>
                                    </div> -->
                                </div>
                            </div>

                            <!-- No Results -->
                            <div v-else-if="!isLoading" class="text-center p-5">
                                <em class="fa fa-search fa-3x text-muted mb-3"></em>
                                <p class="text-muted">{{ $t('NoResultsFound') || 'No results found' }}</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <!-- Pagination -->
            <div class="row mt-4" v-if="totalPages > 1">
                <div class="col-12">
                    <div class="pagination-wrapper">
                        <nav aria-label="Search results pagination">
                            <ul class="pagination justify-content-center mb-2">
                                <li class="page-item" :class="{ disabled: currentPage === 1 }">
                                    <a class="page-link" href="javascript:;" @click.prevent="goToPage(currentPage - 1)">
                                        <em class="fa fa-chevron-left"></em>
                                    </a>
                                </li>
                                <li 
                                    v-for="page in visiblePages" 
                                    :key="page"
                                    class="page-item"
                                    :class="{ active: page === currentPage }"
                                >
                                    <a class="page-link" href="javascript:;" @click.prevent="goToPage(page)">
                                        {{ page }}
                                    </a>
                                </li>
                                <li class="page-item" :class="{ disabled: currentPage === totalPages }">
                                    <a class="page-link" href="javascript:;" @click.prevent="goToPage(currentPage + 1)">
                                        <em class="fa fa-chevron-right"></em>
                                    </a>
                                </li>
                            </ul>
                        </nav>
                        <div class="text-center">
                            <small class="text-muted pagination-info">
                                Showing {{ ((currentPage - 1) * pageSize) + 1 }} to {{ Math.min(currentPage * pageSize, totalCount) }} of {{ totalCount }} results
                            </small>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import DataService from "../../services/DataService";
import Loader from "../../components/Common/Loader.vue";

export default {
    components: {
        Loader
    },
    data() {
        return {
            searchQuery: '',
            searchResults: [],
            isLoading: false,
            currentPage: 1,
            pageSize: 20,
            totalCount: 0,
            totalPages: 0,
            availableModules: [],
            moduleListData: [], // Store full module objects from API
            selectedModules: [],
            selectedModule: '', // Single selected module for dropdown
            moduleCounts: {},
            showModulesDropdown: false,
            moduleSearchQuery: '',
            filteredModules: [],
        }
    },
    computed: {
        displayedResults() {
            // Filter by selected module if any is selected
            if (this.selectedModule) {
                return this.searchResults.filter(r => 
                    r.type === this.selectedModule
                );
            }
            return this.searchResults;
        },
        visiblePages() {
            var pages = [];
            var start = Math.max(1, this.currentPage - 2);
            var end = Math.min(this.totalPages, this.currentPage + 2);
            for (var i = start; i <= end; i++) {
                pages.push(i);
            }
            return pages;
        }
    },
    created() {
        this.loadAvailableModules();
        this.loadSearchResults();
    },
    watch: {
        '$route'(to, from) {
            if (to.query.q !== from.query.q) {
                this.searchQuery = to.query.q || '';
                this.loadSearchResults();
            }
        }
    },
    methods: {
        loadSearchResults() {
            var vm = this;
            
            // Get query from URL parameters
            var urlParams = new URLSearchParams(window.location.search);
            vm.searchQuery = urlParams.get('q') || '';
            var modules = urlParams.get('modules');
            vm.currentPage = parseInt(urlParams.get('page')) || 1;
            
            if (!vm.searchQuery || vm.searchQuery.trim() === '') {
                vm.goHome();
                return;
            }

            vm.isLoading = true;

            // Parse modules if provided
            if (modules) {
                vm.selectedModule = modules.split(',')[0].trim(); // Use first module for single dropdown
                vm.selectedModules = [vm.selectedModule]; // Keep for compatibility
            }

            // Build URL - use server-side pagination
            var modulesParam = '';
            if (vm.selectedModule) {
                modulesParam = '&modules=' + vm.selectedModule;
            }
            
            var url = `searchQuery=${encodeURIComponent(vm.searchQuery)}&pageNumber=${vm.currentPage}&pageSize=${vm.pageSize}${modulesParam}`;
            
            DataService.GlobalSearch(url).then(function(response) {
                vm.isLoading = false;
                console.log('Search Results Response:', response);
                
                if (response && response.data) {
                    var results = response.data.results || [];
                    vm.searchResults = results;
                    
                    // Use totalCount from API
                    vm.totalCount = response.data.totalCount || 0;
                    vm.totalPages = response.data.totalPages || Math.ceil(vm.totalCount / vm.pageSize) || 1;
                    vm.moduleCounts = response.data.moduleCounts || {};
                    
                    console.log('Search Results Count:', results.length);
                    console.log('Total Count:', vm.totalCount);
                    console.log('Total Pages:', vm.totalPages);
                    console.log('Module Counts:', vm.moduleCounts);
                    
                    // Load available modules from GetModuleList API
                    vm.loadAvailableModules();
                } else {
                    console.warn('No data in response:', response);
                    vm.searchResults = [];
                    vm.totalCount = 0;
                    vm.totalPages = 0;
                }
            }).catch(function(error) {
                console.error('Search error:', error);
                console.error('Error details:', error.response || error.message);
                vm.isLoading = false;
                vm.searchResults = [];
                vm.totalCount = 0;
                vm.totalPages = 0;
            });
        },
        
        toggleModulesDropdown() {
            this.showModulesDropdown = !this.showModulesDropdown;
        },
        
        filterModules() {
            var vm = this;
            if (!vm.moduleSearchQuery || vm.moduleSearchQuery.trim() === '') {
                vm.filteredModules = vm.availableModules;
            } else {
                var query = vm.moduleSearchQuery.toLowerCase();
                vm.filteredModules = vm.availableModules.filter(m => {
                    var moduleText = (m.text || m.moduleName || m.ModuleName || m.name || m.Name || m).toLowerCase();
                    return moduleText.includes(query);
                });
            }
        },
        
        getModuleDisplayName(module) {
            var vm = this;
            
            // Find module in API data from database
            if (vm.moduleListData && vm.moduleListData.length > 0) {
                var moduleObj = vm.moduleListData.find(function(m) {
                    var moduleName = m.moduleName || m.ModuleName || m.name || m.Name || m;
                    return moduleName === module || 
                           (typeof moduleName === 'string' && moduleName.toLowerCase() === module.toLowerCase());
                });
                
                if (moduleObj) {
                    // Use display name from database
                    var displayName = moduleObj.displayName || moduleObj.DisplayName || 
                                     moduleObj.moduleDisplayName || moduleObj.ModuleDisplayName ||
                                     moduleObj.moduleName || moduleObj.ModuleName || 
                                     moduleObj.name || moduleObj.Name;
                    
                    if (displayName) {
                        return displayName;
                    }
                }
            }
            
            // If not found in database, return the module name as-is
            return module || 'Unknown Module';
        },

        onModuleFilterChange() {
            var vm = this;
            // Update selectedModules array from single dropdown
            if (vm.selectedModule) {
                vm.selectedModules = [vm.selectedModule];
            } else {
                vm.selectedModules = [];
            }
            // Filter is done client-side, just update URL and reset to page 1
            vm.currentPage = 1;
            vm.updateUrl();
            // Note: We don't reload from server since API doesn't support module filtering
            // Results are filtered client-side via computed property
        },

        clearModuleFilter() {
            this.selectedModule = '';
            this.selectedModules = [];
            this.currentPage = 1;
            this.updateUrl();
            // Note: We don't reload from server since API doesn't support module filtering
            // Results are filtered client-side via computed property
        },

        loadAvailableModules() {
            var vm = this;
            // Load available modules from API
            DataService.GetModuleList().then(function(response) {
                if (response && response.data) {
                    // Handle different response formats
                    var modules = [];
                    if (Array.isArray(response.data)) {
                        modules = response.data;
                    } else if (response.data.data && Array.isArray(response.data.data)) {
                        modules = response.data.data;
                    } else if (response.data.result && Array.isArray(response.data.result)) {
                        modules = response.data.result;
                    }
                    
                    // Store full module objects
                    vm.moduleListData = modules;
                    
                    // Map modules to objects with text and value properties
                    if (modules.length > 0) {
                        vm.availableModules = modules.map(function(module) {
                            var moduleText = module.text || module.moduleName || module.ModuleName || module.name || module.Name || module;
                            var moduleValue = module.value || module.moduleName || module.ModuleName || module.name || module.Name || module;
                            
                            // Map display names to values
                            if (moduleText === "Client Bill") {
                                moduleValue = "Talygen_bill";
                            } else if (moduleText === "Clients") {
                                moduleValue = "Talygen_user";
                            } else if (moduleText === "Projects") {
                                moduleValue = "Talygen_Project";
                            } else if (moduleText === "Ticketing") {
                                moduleValue = "Talygen_ticketing";
                            }
                            
                            return {
                                text: moduleText,
                                value: moduleValue
                            };
                        }).filter(function(m) { return m && m.text; });
                     
                    } else {
                        // Default modules if API doesn't return them
                        vm.availableModules = [
                            { text: 'B Billing', value: 'Talygen_bill' },
                            { text: 'U User', value: 'Talygen_user' }
                        ];
                        vm.moduleListData = [];
                    }
                } else {
                    // Default modules if API doesn't return them
                    vm.availableModules = [
                        { text: 'B Billing', value: 'Talygen_bill' },
                        { text: 'U User', value: 'Talygen_user' }
                    ];
                    vm.moduleListData = [];
                }
                vm.filteredModules = vm.availableModules;
            }).catch(function(error) {
                console.error('Error loading modules:', error);
                // Default modules if API fails
                vm.availableModules = [
                    { text: 'B Billing', value: 'Talygen_bill' },
                    { text: 'U User', value: 'Talygen_user' }
                ];
                vm.moduleListData = [];
                vm.filteredModules = vm.availableModules;
            });
        },

        goToPage(page) {
            if (page >= 1 && page <= this.totalPages && page !== this.currentPage) {
                this.currentPage = page;
                this.updateUrl();
                this.loadSearchResults();
                this.scrollToTop();
            }
        },

        updateUrl() {
            var vm = this;
            var url = new URL(window.location.href);
            url.searchParams.set('q', vm.searchQuery);
            url.searchParams.set('page', vm.currentPage);
            if (vm.selectedModule) {
                url.searchParams.set('modules', vm.selectedModule);
            } else {
                url.searchParams.delete('modules');
            }
            window.history.pushState({}, '', url);
        },

        navigateToResult(result) {
            var vm = this;
            if (!result || !result.url) {
                return;
            }
            
            if (result.isExternal) {
                window.location.href = result.url;
            } else {
                // Navigate to the URL (could be in different app in single-SPA)
                window.location.href = result.url;
            }
        },

        goBack() {
            if (window.history.length > 1) {
                window.history.back();
            } else {
                this.goHome();
            }
        },

        goHome() {
            window.location.href = '/';
        },

        scrollToTop() {
            window.scrollTo({ top: 0, behavior: 'smooth' });
        },

        highlightText(text, query) {
            if (!text || !query) {
                return text || '';
            }
            
            var regex = new RegExp('(' + this.escapeRegex(query) + ')', 'gi');
            return text.replace(regex, '<mark>$1</mark>');
        },

        escapeRegex(string) {
            return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        },

        formatDate(date) {
            if (!date) return 'N/A';
            try {
                var d = new Date(date);
                if (isNaN(d.getTime())) return date;
                var month = (d.getMonth() + 1).toString().padStart(2, '0');
                var day = d.getDate().toString().padStart(2, '0');
                var year = d.getFullYear();
                return month + '/' + day + '/' + year;
            } catch (e) {
                return date;
            }
        },

        formatCurrency(amount) {
            if (!amount && amount !== 0) return 'N/A';
            try {
                return parseFloat(amount).toLocaleString('en-US', {
                    style: 'currency',
                    currency: 'USD',
                    minimumFractionDigits: 2
                });
            } catch (e) {
                return amount;
            }
        },
        
        handleAttach(result) {
            // Handle attach action
            console.log('Attach clicked for:', result);
            // Add your attach logic here
        },
        
        handleSummarize(result) {
            // Handle summarize action
            console.log('Summarize clicked for:', result);
            // Add your summarize logic here
        },

        parseDisplayText(result) {
            // Try to parse display_text as JSON
            if (!result.title) {
                return null;
            }
            
            try {
                var title = result.title.trim();
                // Check if title is JSON string (may be truncated with ...)
                if (title.startsWith('{')) {
                    // Handle truncated JSON (ends with ...)
                    if (title.endsWith('...')) {
                        title = title.replace(/\.\.\.$/, '');
                        // Try to close the JSON object
                        if (!title.endsWith('}')) {
                            title += '}';
                        }
                    }
                    // Ensure it ends with }
                    if (!title.endsWith('}')) {
                        title += '}';
                    }
                    return JSON.parse(title);
                }
            } catch (e) {
                // Not valid JSON, return null
                console.debug('Failed to parse JSON:', e);
            }
            
            return null;
        },

        getParsedField(result, fieldName) {
            var parsed = this.parseDisplayText(result);
            if (parsed && parsed[fieldName]) {
                return parsed[fieldName];
            }
            return null;
        },

        isInvoiceResult(result) {
            return result.type === 'Invoice' || result.type === 'Talygen_bill' || 
                   (result.type && result.type.toLowerCase().includes('bill'));
        },

        isUserResult(result) {
            return result.type === 'Talygen_user' || result.type === 'User' ||
                   (result.type && result.type.toLowerCase().includes('user'));
        },

        getResultId(result) {
            var parsed = this.parseDisplayText(result);
            
            // For invoices, extract invoice_no from JSON
            if (this.isInvoiceResult(result)) {
                // if (parsed && parsed.invoice_no) {
                //     // Extract invoice number from "Invoice No. INV268848"
                //     var invoiceMatch = parsed.invoice_no.match(/(INV\d+)/i);
                //     if (invoiceMatch) {
                //         return invoiceMatch[1];
                //     }
                //     return parsed.invoice_no;
                // }
                // Fallback: try to extract from title
                // if (result.title) {
                //     var invoiceIdMatch = result.title.match(/(INV\d+)/i);
                //     if (invoiceIdMatch) {
                //         return invoiceIdMatch[1];
                //     }
                // }
                return parsed.invoice_no;
            }
            
            // For users, show user_id from JSON
            if (this.isUserResult(result)) {
                if (parsed && parsed.user_id) {
                    return parsed.user_id;
                }
            }
            
            // Default: return ID or first part of title
            return result.id || (result.title ? result.title.split(/\s+/)[0] : 'N/A');
        },

        getResultDescription(result) {
            var parsed = this.parseDisplayText(result);
            
            // For invoices, get contract_name or usre_name from JSON
            if (this.isInvoiceResult(result)) {
                if (parsed) {
                    if (parsed.contract_name) {
                        return parsed.contract_name;
                    }
                    if (parsed.usre_name) {
                        return parsed.usre_name;
                    }
                }
            }
            
            // For users, show usre_name or contract_name from JSON
            if (this.isUserResult(result)) {
                if (parsed) {
                    if (parsed.usre_name) {
                        return parsed.usre_name;
                    }
                    if (parsed.contract_name) {
                        return parsed.contract_name;
                    }
                }
            }
            
            // Default: return subtitle or empty
            return result.subtitle || '';
        }
    }
}
</script>

<style>
.search-results-page {
    padding: 20px;
    background: #f5f5f5;
    min-height: calc(100vh - 100px);
}

.search-results-container {
    padding: 0;
}

.search-result-item {
    display: flex;
    align-items: flex-start;
    padding: 0;
    border-bottom: 1px solid #e0e0e0;
    transition: background-color 0.2s;
    /* cursor: pointer; */
    gap: 8px;
}

.search-result-item:hover {
    background-color: #f8f9fa;
}

.search-result-item:last-child {
    border-bottom: none;
}

.result-icon {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    /* background: #f0f0f0; */
    border-radius: 4px;
    flex-shrink: 0;
    margin-top: 2px;
}

.result-icon em {
    font-size: 16px;
    color: #6c757d;
}

.result-content {
    flex: 1;
